require"UI.UIBase"require"UI.UIBlock"require"Net.NetCore.GatewayFetcher"require"Net.NetCore.NetRouteGroup_Entrance"local a=require("PrintTable")require"ProtoMgr"require"UIMgr"UI_SerRoot=UIBase:Inherit()UI_SerRoot.UI_BtnPanel=UIBlock:Inherit()local b=require'cjson'local c=Tools.HexToColor("#FFFFFF")local d=Tools.HexToColor("#29B000")function UI_SerRoot:OnCreate()UI_SerRoot.Inst=self;self.serverData=GameMgr.Inst.config_data;self.serverRoot=self.transform:GetComponent(typeof(NormalUList))self.serverRoot:InitTemp(#self.serverData.ip)self.serverRoot:InitValue()self.serverRoot:SetFunc(function(e,f)UI_SerRoot:UpdateItem(e,f)end)self.serverRoot:InitPos(#self.serverData.ip)end;function UI_SerRoot:OnShow(g)if not GameMgr.Inst.test_server then self.transform.gameObject:SetActive(false)self:ChooseServer(1)else self.transform.gameObject:SetActive(true)g()end end;function UI_SerRoot:ChooseServer(h)local i=UI_SerRoot.Inst.serverData.ip[h]LogTool.Info('SelectServer','连接到服务器：'..i.name)GameMgr.Inst.zone_config=i.zone_id;GameMgr.Inst.backup_urls=i.backup_urls;local j=i.override_email_url;if j~=nil then LogTool.Info('SelectServer','override email url: '..j)GameMgr.Inst.override_email_url=j end;local k=i.server_environment;if k~=nil then LogTool.Info('SelectServer','server_environment: '..k)GameMgr.Inst.server_environment=k;GameMgr.Inst.inRelease=k=='R'end;local l=i.prefix_url;if l~=nil then LogTool.Info('SelectServer','paipu prefix_url : '..l)GameMgr.Inst.prefix_url=l end;local m=i.contest_gm_url;if m then GameMgr.Inst.contest_gm_url=i.contest_gm_url end;local n=i.gateways;GatewayFetcher.Init(n)UI_SerRoot.Inst:AfterChooseServer()end;function UI_SerRoot:OnClose(g)self.transform.gameObject:SetActive(false)g()end;function UI_SerRoot:UpdateItem(e,h)local o=e.transform:Find("Text"):GetComponent(typeof(UnityEngine.UI.Text))o.text=UI_SerRoot.Inst.serverData.ip[h+1].name;local p=e.transform:GetComponent(typeof(UnityEngine.UI.Button))p.onClick:RemoveAllListeners()local q=self;p.onClick:AddListener(function()self:ChooseServer(h+1)end)if Tools.IsPC()then e.transform:GetComponent(typeof(EventTriggers)).OnPointerEnterRaised=function()e.transform:Find("Bound").gameObject:SetActive(true)o.color=d end;e.transform:GetComponent(typeof(EventTriggers)).OnPointerExitRaised=function()e.transform:Find("Bound").gameObject:SetActive(false)o.color=c end end end;function UI_SerRoot:AfterChooseServer()self:CloseSelf()UIMgr.Inst:ShowUI(UI_Entrance.className,function()if GameMgr.Inst.client_language~='chs_t'then self:AnimAlphaIn(UI_Entrance.Inst.transform,{x=0,y=0},1)else self:AnimAlphaIn(UI_Entrance.Inst.transform,{x=0,y=0},0.01)end end)end;function UI_SerRoot:CloseLog()local r=UnityEngine.GameObject.Find('root_debug')if r then r:SetActive(false)end end;return UI_SerRoot